-- ============================================================================
-- POLICIES
-- ============================================================================
insert into policies (topic, title, content) values
  ('returns', 'Standard Return Policy', 'Cupboard accepts returns on most items within 30 days of delivery. Items must be unused, in original packaging, and accompanied by proof of purchase. Once we receive and inspect the return, refunds are issued to the original payment method within 5-10 business days. Return shipping is free for Plus and VIP members; Standard customers pay a flat $7.95 return shipping fee. Final sale items, custom orders, and items marked ''as-is'' cannot be returned.'),
  ('returns', 'Damaged or Defective Items', 'If your item arrives damaged or defective, contact us within 7 days of delivery. We will arrange a free replacement or full refund including shipping. Photos of the damage are required to process the claim. Damaged items do not need to be returned in most cases.'),
  ('shipping', 'Shipping Rates and Timing', 'Standard shipping is $8.95 and arrives in 5-7 business days. Free standard shipping on orders over $75. Expedited shipping (2-3 business days) is $18.95. Orders placed before 12pm ET ship same day. We do not currently ship internationally or to PO boxes. Some oversized items (rugs, large furniture) ship via freight and may take 7-14 business days.'),
  ('shipping', 'Lost or Delayed Packages', 'If your package is marked delivered but you have not received it, please check with neighbors and your local carrier within 48 hours. If the package cannot be located after 48 hours, contact us and we will file a claim with the carrier. For packages tracking as delayed beyond their estimated delivery date by more than 5 business days, we will issue a refund or send a replacement at our discretion.'),
  ('warranty', 'Warranty and Quality Guarantee', 'All Cupboard products are guaranteed against manufacturing defects for one year from purchase date. This warranty does not cover normal wear and tear, misuse, or damage from improper care. To file a warranty claim, contact us with your order number and photos of the issue.'),
  ('account', 'Account and Membership', 'Cupboard Plus is our free loyalty program offering free returns and early access to new collections. VIP membership is by invitation only and includes free expedited shipping, dedicated support, and exclusive product previews. Customers can update account details, payment methods, and shipping addresses by signing into their account at cupboard.com/account.');
